 {"id":"bd-1v08","title":"Unit tests for WebSocket setState safety","description":"## Purpose
Comprehensive unit tests for the useMountedRef pattern ensuring no setState calls occur after component unmount in WebSocket callbacks.

## Test File Location
`apps/web/src/lib/__tests__/websocket-context.unmount.test.tsx`

## Test Cases

### 1. useMountedRef Hook Tests
```typescript
describe("useMountedRef", () => {
  it("should return true while component is mounted", () => {
    const { result } = renderHook(() => useMountedRef());
    expect(result.current.current).toBe(true);
    console.log("[TEST] useMountedRef returns true while mounted");
  });

  it("should return false after component unmounts", () => {
    const { result, unmount } = renderHook(() => useMountedRef());
    expect(result.current.current).toBe(true);

    unmount();

    expect(result.current.current).toBe(false);
    console.log("[TEST] useMountedRef returns false after unmount");
  });

  it("should handle rapid mount/unmount cycles", () => {
    for (let i = 0; i < 10; i++) {
      const { result, unmount } = renderHook(() => useMountedRef());
      expect(result.current.current).toBe(true);
      unmount();
      expect(result.current.current).toBe(false);
    }
    console.log("[TEST] useMountedRef handles rapid mount/unmount cycles");
  });
});
```

### 2. WebSocket Provider Unmount Safety
```typescript
describe("WebSocketProvider - unmount safety", () => {
  let mockWebSocket: MockWebSocket;
  let consoleErrorSpy: jest.SpyInstance;

  beforeEach(() => {
    mockWebSocket = new MockWebSocket();
    global.WebSocket = jest.fn(() => mockWebSocket) as any;
    consoleErrorSpy = jest.spyOn(console, "error").mockImplementation();
  });

  afterEach(() => {
    consoleErrorSpy.mockRestore();
  });

  it("should NOT call setState when onopen fires after unmount", async () => {
    const { unmount } = render(
      <WebSocketProvider url="ws://test">
        <TestConsumer />
      </WebSocketProvider>
    );

    // Unmount before connection opens
    unmount();
    console.log("[TEST] Component unmounted before ws.onopen");

    // Simulate WebSocket opening after unmount
    act(() => {
      mockWebSocket.triggerOpen();
    });
    console.log("[TEST] ws.onopen triggered after unmount");

    // Should NOT have React warning
    expect(consoleErrorSpy).not.toHaveBeenCalledWith(
      expect.stringContaining("unmounted component")
    );
    console.log("[TEST] PASS: No React warning for setState on unmounted");
  });

  it("should NOT call setState when onmessage fires after unmount", async () => {
    const { unmount } = render(
      <WebSocketProvider url="ws://test">
        <TestConsumer />
      </WebSocketProvider>
    );

    // Establish connection
    act(() => mockWebSocket.triggerOpen());

    // Unmount
    unmount();
    console.log("[TEST] Component unmounted while connected");

    // Receive message after unmount
    act(() => {
      mockWebSocket.triggerMessage({ type: "update", data: {} });
    });
    console.log("[TEST] ws.onmessage triggered after unmount");

    expect(consoleErrorSpy).not.toHaveBeenCalledWith(
      expect.stringContaining("unmounted component")
    );
  });

  it("should NOT call setState when onerror fires after unmount", async () => {
    const { unmount } = render(
      <WebSocketProvider url="ws://test">
        <TestConsumer />
      </WebSocketProvider>
    );

    unmount();

    act(() => {
      mockWebSocket.triggerError(new Error("Connection failed"));
    });

    expect(consoleErrorSpy).not.toHaveBeenCalledWith(
      expect.stringContaining("unmounted component")
    );
  });

  it("should NOT call setState when onclose fires after unmount", async () => {
    const { unmount } = render(
      <WebSocketProvider url="ws://test">
        <TestConsumer />
      </WebSocketProvider>
    );

    act(() => mockWebSocket.triggerOpen());
    unmount();

    act(() => {
      mockWebSocket.triggerClose({ code: 1000, reason: "Normal close" });
    });

    expect(consoleErrorSpy).not.toHaveBeenCalledWith(
      expect.stringContaining("unmounted component")
    );
    console.log("[TEST] PASS: onclose safe after unmount");
  });
});
```

### 3. WebSocket Cleanup Verification
```typescript
describe("WebSocketProvider - cleanup on unmount", () => {
  it("should close WebSocket on unmount", () => {
    const closeSpy = jest.fn();
    mockWebSocket.close = closeSpy;

    const { unmount } = render(
      <WebSocketProvider url="ws://test">
        <TestConsumer />
      </WebSocketProvider>
    );

    act(() => mockWebSocket.triggerOpen());
    unmount();

    expect(closeSpy).toHaveBeenCalled();
    console.log("[TEST] WebSocket.close() called on unmount");
  });

  it("should not attempt reconnection after unmount", async () => {
    jest.useFakeTimers();

    const { unmount } = render(
      <WebSocketProvider url="ws://test" reconnectInterval={1000}>
        <TestConsumer />
      </WebSocketProvider>
    );

    // Connection fails, triggering reconnect
    act(() => mockWebSocket.triggerClose({ code: 1006 }));

    // Unmount before reconnect timer fires
    unmount();

    // Advance past reconnect interval
    act(() => jest.advanceTimersByTime(2000));

    // WebSocket constructor should NOT be called again
    expect(global.WebSocket).toHaveBeenCalledTimes(1);
    console.log("[TEST] No reconnection attempt after unmount");

    jest.useRealTimers();
  });
});
```

### 4. Async Callback Safety (useCAAM)
```typescript
describe("useCAAM - async callback safety", () => {
  it("should NOT update state after unmount in async fetch", async () => {
    let resolvePromise: (value: any) => void;
    const mockFetch = jest.fn(() => new Promise(r => { resolvePromise = r; }));

    const { unmount } = renderHook(() => useCAAM(), {
      wrapper: ({ children }) => (
        <MockAPIProvider fetch={mockFetch}>{children}</MockAPIProvider>
      ),
    });

    // Trigger async operation
    act(() => {
      // Start fetch that will complete after unmount
    });

    unmount();
    console.log("[TEST] Component unmounted while fetch pending");

    // Resolve the promise after unmount
    await act(async () => {
      resolvePromise({ accounts: [] });
    });

    expect(consoleErrorSpy).not.toHaveBeenCalledWith(
      expect.stringContaining("unmounted component")
    );
    console.log("[TEST] PASS: Async fetch result ignored after unmount");
  });
});
```

### 5. Memory Leak Detection
```typescript
describe("WebSocketProvider - memory leaks", () => {
  it("should not leak event listeners after unmount", () => {
    const addListenerSpy = jest.spyOn(mockWebSocket, "addEventListener");
    const removeListenerSpy = jest.spyOn(mockWebSocket, "removeEventListener");

    const { unmount } = render(
      <WebSocketProvider url="ws://test">
        <TestConsumer />
      </WebSocketProvider>
    );

    act(() => mockWebSocket.triggerOpen());
    const listenersAdded = addListenerSpy.mock.calls.length;

    unmount();

    // All listeners should be removed
    expect(removeListenerSpy.mock.calls.length).toBeGreaterThanOrEqual(listenersAdded);
    console.log(`[TEST] ${listenersAdded} listeners added, ${removeListenerSpy.mock.calls.length} removed`);
  });

  it("should clear all timeouts/intervals on unmount", () => {
    jest.useFakeTimers();
    const clearTimeoutSpy = jest.spyOn(global, "clearTimeout");
    const clearIntervalSpy = jest.spyOn(global, "clearInterval");

    const { unmount } = render(
      <WebSocketProvider url="ws://test" pingInterval={5000}>
        <TestConsumer />
      </WebSocketProvider>
    );

    act(() => mockWebSocket.triggerOpen());
    unmount();

    // Should have cleared ping interval at minimum
    expect(clearIntervalSpy.mock.calls.length + clearTimeoutSpy.mock.calls.length)
      .toBeGreaterThan(0);
    console.log("[TEST] Timers cleared on unmount");

    jest.useRealTimers();
  });
});
```

## Mock WebSocket Implementation
```typescript
// __tests__/mocks/MockWebSocket.ts
export class MockWebSocket {
  onopen: ((e: Event) => void) | null = null;
  onmessage: ((e: MessageEvent) => void) | null = null;
  onerror: ((e: Event) => void) | null = null;
  onclose: ((e: CloseEvent) => void) | null = null;

  triggerOpen() {
    this.onopen?.(new Event("open"));
  }

  triggerMessage(data: any) {
    this.onmessage?.(new MessageEvent("message", { data: JSON.stringify(data) }));
  }

  triggerError(error: Error) {
    this.onerror?.(new ErrorEvent("error", { error }));
  }

  triggerClose(opts: { code: number; reason?: string }) {
    this.onclose?.(new CloseEvent("close", opts));
  }

  close = jest.fn();
  send = jest.fn();
}
```

